-- PASSO 1: Criar tabela products
CREATE TABLE IF NOT EXISTS public.products (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  category text NOT NULL DEFAULT 'outros',
  billing_type text NOT NULL DEFAULT 'recurring'
    CHECK (billing_type IN ('recurring', 'one_time')),
  default_price numeric(12,2) NOT NULL DEFAULT 0,
  description text,
  active boolean NOT NULL DEFAULT true,
  v4_product_id uuid,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.products ENABLE ROW LEVEL SECURITY;

CREATE POLICY "allow all authenticated"
  ON public.products FOR ALL
  USING (auth.role() = 'authenticated')
  WITH CHECK (auth.role() = 'authenticated');

-- PASSO 2: Criar tabela product_materials
CREATE TABLE IF NOT EXISTS public.product_materials (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  product_id uuid NOT NULL REFERENCES public.products(id) ON DELETE CASCADE,
  name text NOT NULL,
  url text,
  type text NOT NULL DEFAULT 'operacional'
    CHECK (type IN ('comercial', 'operacional', 'treinamento')),
  formato text DEFAULT 'material',
  active boolean NOT NULL DEFAULT true,
  v4_material_id uuid,
  created_at timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.product_materials ENABLE ROW LEVEL SECURITY;

CREATE POLICY "allow all authenticated"
  ON public.product_materials FOR ALL
  USING (auth.role() = 'authenticated')
  WITH CHECK (auth.role() = 'authenticated');

